// Faktisk Studio · Looping Video-plugin
// URL → preview → trim (maks 10 sek) → embed-snippet til clipboard

const PLUGIN_ID = 'looping-video';
const MAX_DURATION = 10;  // sekunder — maksimum lengde på looping-klipp
const MIN_DURATION = 1;   // sekunder — minimum, kortere blir bare et rykk

const els = {
  url:           document.getElementById('videoUrl'),
  loadBtn:       document.getElementById('loadVideoBtn'),
  video:         document.getElementById('videoEl'),
  empty:         document.getElementById('canvasEmpty'),
  track:         document.getElementById('track'),
  selection:     document.getElementById('selection'),
  handleStart:   document.getElementById('handleStart'),
  handleEnd:     document.getElementById('handleEnd'),
  labelStart:    document.getElementById('labelStart'),
  labelEnd:      document.getElementById('labelEnd'),
  labelDuration: document.getElementById('labelDuration'),
  copyEmbed:     document.getElementById('copyEmbedBtn'),
  exportVideo:   document.getElementById('exportVideoBtn'),
  status:        document.getElementById('status'),
  back:          document.getElementById('backBtn'),
  full:          document.getElementById('fullscreenBtn'),
  captionText:   document.getElementById('captionText'),
  photographer:  document.getElementById('photographerText'),
  openLabrador:  document.getElementById('openLabradorBtn'),
  projectSelect: document.getElementById('projectSelect'),
  saveProject:   document.getElementById('saveProjectBtn'),
};

const state = {
  url: '',
  duration: 0,
  trimStart: 0,
  trimEnd: 0,
  loaded: false,
};

// ============================================================
//  Last video — kobler URL til <video>
// ============================================================
function setStatus(msg, isError) {
  els.status.textContent = msg || '';
  els.status.style.color = isError ? '#FFB4B4' : '#fff';
}

function isValidUrl(s) {
  try {
    const u = new URL(s);
    return u.protocol === 'http:' || u.protocol === 'https:';
  } catch (e) { return false; }
}

async function loadVideo() {
  const url = els.url.value.trim();
  if (!url) {
    setStatus('Lim inn en URL først.', true);
    return;
  }
  if (!isValidUrl(url)) {
    setStatus('Det ser ikke ut som en gyldig URL.', true);
    return;
  }
  setStatus('Laster…');
  els.video.src = url;
  // metadata gir oss varigheten — vent på den
  await new Promise((resolve, reject) => {
    const onMeta = () => { cleanup(); resolve(); };
    const onErr = (e) => { cleanup(); reject(new Error('Kunne ikke laste videoen — sjekk URL.')); };
    function cleanup() {
      els.video.removeEventListener('loadedmetadata', onMeta);
      els.video.removeEventListener('error', onErr);
    }
    els.video.addEventListener('loadedmetadata', onMeta);
    els.video.addEventListener('error', onErr);
  }).catch(err => {
    setStatus(err.message, true);
    state.loaded = false;
    updateExportButtons();
    return null;
  });

  if (!els.video.duration || !isFinite(els.video.duration)) {
    setStatus('Klarte ikke å lese videoens lengde.', true);
    return;
  }

  state.url = url;
  state.duration = els.video.duration;
  state.trimStart = 0;
  state.trimEnd = Math.min(MAX_DURATION, state.duration);
  state.loaded = true;

  els.empty.classList.add('hidden');
  renderTimeline();
  syncVideoToSelection();
  startPreviewLoop();
  updateExportButtons();
  setStatus(`Lastet · ${Math.round(els.video.videoWidth)}×${Math.round(els.video.videoHeight)} · ${formatSec(state.duration)}`);
  scheduleSaveState();
}

// ============================================================
//  Preview-loop — looper trimStart til trimEnd
// ============================================================
function startPreviewLoop() {
  els.video.currentTime = state.trimStart;
  els.video.play().catch(() => {});
  els.video.ontimeupdate = () => {
    if (els.video.currentTime >= state.trimEnd - 0.05) {
      els.video.currentTime = state.trimStart;
    }
  };
}

function syncVideoToSelection() {
  if (els.video.currentTime < state.trimStart || els.video.currentTime > state.trimEnd) {
    els.video.currentTime = state.trimStart;
  }
}

// ============================================================
//  Tidslinje
// ============================================================
function renderTimeline() {
  const dur = state.duration;
  if (!dur) return;
  const startPct = (state.trimStart / dur) * 100;
  const endPct = (state.trimEnd / dur) * 100;
  els.handleStart.style.left = startPct + '%';
  els.handleEnd.style.left = endPct + '%';
  els.selection.style.left = startPct + '%';
  els.selection.style.width = (endPct - startPct) + '%';
  els.labelStart.textContent = formatSec(state.trimStart);
  els.labelEnd.textContent = formatSec(state.trimEnd);
  els.labelDuration.textContent = formatSec(state.trimEnd - state.trimStart);
}

function formatSec(s) {
  return s.toFixed(1).replace('.', ',') + 's';
}

function attachHandleDrag(handle, isStart) {
  handle.addEventListener('mousedown', e => {
    e.preventDefault();
    const trackRect = els.track.getBoundingClientRect();
    const onMove = (ev) => {
      const x = Math.max(0, Math.min(trackRect.width, ev.clientX - trackRect.left));
      const pct = x / trackRect.width;
      const t = pct * state.duration;
      if (isStart) {
        // Start må være ≥0 og ≤ end - MIN_DURATION
        state.trimStart = Math.max(0, Math.min(t, state.trimEnd - MIN_DURATION));
        // Klipp som ikke overskrider MAX_DURATION
        if (state.trimEnd - state.trimStart > MAX_DURATION) {
          state.trimEnd = state.trimStart + MAX_DURATION;
        }
      } else {
        state.trimEnd = Math.min(state.duration, Math.max(t, state.trimStart + MIN_DURATION));
        if (state.trimEnd - state.trimStart > MAX_DURATION) {
          state.trimStart = state.trimEnd - MAX_DURATION;
        }
      }
      renderTimeline();
      syncVideoToSelection();
    };
    const onUp = () => {
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
      scheduleSaveState();   // lagre etter at brukeren slipper håndtaket
    };
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  });
}

attachHandleDrag(els.handleStart, true);
attachHandleDrag(els.handleEnd, false);

// ============================================================
//  Generer embed-snippet
// ============================================================
function escapeHtml(s) {
  return String(s).replace(/[<>&"]/g, c => ({
    '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;'
  }[c]));
}

function buildEmbedSnippet() {
  const ts = state.trimStart.toFixed(2);
  const te = state.trimEnd.toFixed(2);
  const baseUrl = state.url.split('#')[0];
  const id = 'fvl-' + Math.random().toString(36).slice(2, 8);
  const caption = (els.captionText.value || '').trim();
  const photographer = (els.photographer.value || '').trim();
  const hasCaption = caption || photographer;

  // Bruk Faktisks egen .caption-klasse (definert i main.css):
  //   .caption{font-size:.9em;margin-top:.5rem}
  //   .caption figcaption{display:inline}
  //   .caption figcaption[itemprop=caption]{margin-right:.3em}
  //   .caption figcaption[itemprop=author]{opacity:.7}
  //   .caption figcaption[itemprop=author]:before{content:attr(data-byline-prefix) " "}
  // Strukturen er .caption-wrapper med to figcaption-elementer (caption + author).
  // "Foto: "-prefiksen kommer automatisk fra data-byline-prefix-attributtet.
  // Font-family arves fra artikkelen (Tiempos Text), så embedet ser ut som
  // alle andre bildetekster på faktisk.no.
  // Bygges med tydelige kommentar-blokker over hver redigerbare del så
  // journalisten vet HVOR i koden de skal endre teksten — ikke i aria-label
  // eller andre tekniske attributter, men i selve figcaption-elementet.
  const captionParts = [];
  if (caption) {
    captionParts.push(`
    <!-- ▶ BILDETEKST -->
    <figcaption itemprop="caption">${escapeHtml(caption)}</figcaption>`);
  }
  if (photographer) {
    captionParts.push(`
    <!-- ▶ FOTOGRAF / KILDE ("Foto: " kommer automatisk) -->
    <figcaption itemprop="author" data-byline-prefix="Foto:">${escapeHtml(photographer)}</figcaption>`);
  }

  const open = hasCaption ? `<figure style="margin:0;">` : '';
  const close = hasCaption ? `</figure>` : '';

  // Bygges som kompakt, redaktør-vennlig HTML:
  //  - Video-tagen er på ÉN linje så den ikke overvelder
  //  - aria-label er en GENERELL etikett (ikke duplikat av bildeteksten)
  //  - Visuelle markører ▶ peker på hver redigerbar del
  //  - Tekniske detaljer (id, loop-script) holdes lavt nede
  const innerCaption = hasCaption ? `

  <div class="caption">${captionParts.join('')}
  </div>` : '';
  return `<!-- ============================================
     FAKTISK · LOOPING VIDEO
     Endre teksten i feltene merket med ▶
     ============================================ -->
${open}
  <!-- ▶ VIDEO — bytt ut URL-en under for å bruke et annet klipp -->
  <video id="${id}" data-src="${baseUrl}#t=${ts},${te}" muted playsinline preload="none" aria-label="Looping videoklipp" style="width:100%;height:auto;border-radius:8px;display:block;background:#000;"></video>${innerCaption}
${close}
<script>
(function(){
  var v=document.getElementById('${id}'); if(!v) return;
  var S=${ts}, E=${te}, loaded=false, inView=false;
  function actuallyLoad(){
    if(loaded) return; loaded=true;
    v.src=v.dataset.src; v.load();
    v.play().catch(function(){});
  }
  function tryLoad(){
    if(loaded || !inView) return;
    if(document.readyState !== 'complete'){
      window.addEventListener('load', tryLoad, {once:true});
      return;
    }
    actuallyLoad();
  }
  v.addEventListener('loadedmetadata',function(){ v.currentTime=S; });
  v.addEventListener('timeupdate',function(){
    if(v.currentTime>=E-0.05){ v.currentTime=S; v.play(); }
  });
  v.addEventListener('ended',function(){ v.currentTime=S; v.play(); });
  if('IntersectionObserver' in window){
    var io=new IntersectionObserver(function(es){
      es.forEach(function(e){ if(e.isIntersecting){ inView=true; tryLoad(); } });
    },{threshold:0.1});
    io.observe(v);
  } else {
    inView=true; tryLoad();
  }
})();
</script>
`;
}

// ============================================================
//  Knapper
// ============================================================
function updateExportButtons() {
  els.copyEmbed.disabled = !state.loaded;
  els.exportVideo.disabled = !state.loaded;
}

els.loadBtn.addEventListener('click', loadVideo);
els.url.addEventListener('keydown', e => {
  if (e.key === 'Enter') loadVideo();
});

els.copyEmbed.addEventListener('click', async () => {
  if (!state.loaded) return;
  const snippet = buildEmbedSnippet();
  try {
    await window.faktisk.copyToClipboard(snippet);
    const orig = els.copyEmbed.textContent;
    els.copyEmbed.textContent = '✅ Kopiert!';
    setStatus('Embed-koden er kopiert — lim inn i Labrador Markup-boks.');
    setTimeout(() => { els.copyEmbed.textContent = orig; }, 2000);
  } catch (e) {
    setStatus('Kunne ikke kopiere: ' + e.message, true);
  }
});

els.exportVideo.addEventListener('click', () => {
  alert('Videoeksport kommer i neste versjon.\n\nInntil da: bruk «Kopier embed-kode» — den genererer en HTML-snutt som peker mot original-videoen i Labrador, med start/slutt-tider satt. Ingen re-encoding nødvendig.');
});

els.back.addEventListener('click', async () => {
  await window.faktisk.goHome();
});

els.full.addEventListener('click', async () => {
  await window.faktisk.toggleFullscreen();
});

els.openLabrador.addEventListener('click', async () => {
  await window.faktisk.openExternal('https://labrador.faktisk.no/settings/upload-file');
});

// ============================================================
//  Arkivering — auto-restore + navngitte prosjekter
// ============================================================

let isRestoring = false;

function serializeState() {
  return {
    url: els.url.value,
    trimStart: state.trimStart,
    trimEnd: state.trimEnd,
    captionText: els.captionText.value,
    photographer: els.photographer.value,
    loaded: state.loaded,
  };
}

async function applyState(saved) {
  if (!saved) return;
  isRestoring = true;
  try {
    els.captionText.value = saved.captionText || '';
    els.photographer.value = saved.photographer || '';
    if (saved.url) {
      els.url.value = saved.url;
      await loadVideo();
      if (state.loaded) {
        if (typeof saved.trimStart === 'number') {
          state.trimStart = Math.max(0, Math.min(saved.trimStart, state.duration));
        }
        if (typeof saved.trimEnd === 'number') {
          state.trimEnd = Math.max(state.trimStart + MIN_DURATION,
                                  Math.min(saved.trimEnd, state.duration));
        }
        renderTimeline();
        syncVideoToSelection();
      }
    }
  } finally {
    isRestoring = false;
  }
}

let saveTimer = null;
function scheduleSaveState() {
  if (isRestoring) return;
  clearTimeout(saveTimer);
  saveTimer = setTimeout(() => {
    window.faktisk.stateSave(PLUGIN_ID, serializeState()).catch(console.error);
  }, 400);
}

// Hook scheduleSaveState på alle endringer
['input', 'change'].forEach(ev => {
  els.url.addEventListener(ev, scheduleSaveState);
  els.captionText.addEventListener(ev, scheduleSaveState);
  els.photographer.addEventListener(ev, scheduleSaveState);
});

// Trim-endringer og load — lagres via eksplisitte kall fra drag/load

// ============================================================
//  Lagre prosjekt + dropdown
// ============================================================

async function refreshProjectList() {
  try {
    const res = await window.faktisk.projectList(PLUGIN_ID);
    if (!res.ok) return;
    const sel = els.projectSelect;
    // Behold første "Velg…" option, fjern resten
    while (sel.options.length > 1) sel.remove(1);
    res.projects.forEach(p => {
      const opt = document.createElement('option');
      opt.value = p.fileId;
      opt.textContent = p.name;
      sel.appendChild(opt);
    });
  } catch (e) { console.error(e); }
}

els.saveProject.addEventListener('click', async () => {
  const defaultName = (els.captionText.value || '').slice(0, 40).trim()
    || `Looping ${new Date().toLocaleDateString('no')}`;
  const name = await window.faktiskDialog.prompt('Lagre prosjekt som:', defaultName);
  if (!name || !name.trim()) return;
  const res = await window.faktisk.projectSave(PLUGIN_ID, name.trim(), serializeState());
  if (res.ok) {
    setStatus('Prosjektet er lagret: «' + res.name + '».');
    await refreshProjectList();
    const fileId = name.trim().replace(/[^a-zA-Z0-9-_]/g, '_').slice(0, 100);
    els.projectSelect.value = fileId;
  } else {
    setStatus('Kunne ikke lagre: ' + (res.error || 'ukjent feil'), true);
  }
});

els.projectSelect.addEventListener('change', async () => {
  const fileId = els.projectSelect.value;
  if (!fileId) return;
  const res = await window.faktisk.projectLoad(PLUGIN_ID, fileId);
  if (res.ok && res.state) {
    setStatus('Åpner «' + res.name + '»…');
    await applyState(res.state);
    setStatus('Åpnet «' + res.name + '».');
  } else {
    setStatus('Kunne ikke åpne prosjekt: ' + (res.error || 'ukjent feil'), true);
  }
});

// ============================================================
//  Init — last forrige tilstand eller åpne valgt prosjekt fra hub
// ============================================================
(async function init() {
  updateExportButtons();
  await refreshProjectList();

  // Hub kan ha bedt om å åpne et spesifikt prosjekt — sjekk localStorage
  const pending = localStorage.getItem('faktisk-pending-project');
  if (pending) {
    try {
      const { pluginId, fileId } = JSON.parse(pending);
      localStorage.removeItem('faktisk-pending-project');
      if (pluginId === PLUGIN_ID) {
        const res = await window.faktisk.projectLoad(pluginId, fileId);
        if (res.ok && res.state) {
          await applyState(res.state);
          els.projectSelect.value = fileId;
          return;
        }
      }
    } catch (e) { console.error(e); }
  }

  // Ellers — last forrige tilstand stille (status-meldingen som overskrives
  // av loadVideo viser allerede "Lastet · 1920×1080 · 3,2s")
  try {
    const res = await window.faktisk.stateLoad(PLUGIN_ID);
    if (res.ok && res.state) {
      await applyState(res.state);
    }
  } catch (e) { console.error(e); }
})();

style.css:
/* ============================================
   LOOPING VIDEO — plugin-spesifikk styling
   Bygger på src/style.css (designsystem)
   ============================================ */

.plugin-page {
  flex: 1;
  display: grid;
  grid-template-columns: 313px 1fr;
  gap: 22px;
  overflow: hidden;
  padding: 4px;
}

/* ============================================
   Venstre sidebar
   ============================================ */
.plugin-sidebar {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding: 0 4px;
}

.plugin-sidebar__title {
  font-family: var(--font-bold);
  font-size: 27px;
  font-weight: bold;
  color: #212121;
  margin: 0;
  line-height: 1.05;
}

.plugin-sidebar__desc {
  font-family: var(--font-regular);
  font-size: 15px;
  color: #fff;
  margin: 0;
  line-height: 1.4;
}

.plugin-sidebar__desc em {
  font-style: normal;
  font-family: var(--font-bold);
  font-weight: bold;
}

.plugin-sidebar__spacer { flex: 1; }

/* Caption + photographer-felter */
.caption-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.caption-input {
  background: var(--bg-input);
  border: 0;
  outline: 0;
  border-radius: var(--radius-input);
  padding: 10px 14px;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 13px;
  color: var(--text-input);
  resize: vertical;
  line-height: 1.35;
  font-family: inherit;
}
.caption-input--single { height: 36px; padding: 8px 14px; }
.caption-input::placeholder {
  color: #888;
  font-weight: normal;
}

.caption-hint {
  font-family: var(--font-regular);
  font-size: 12px;
  color: #fff;
  opacity: 0.75;
  margin: 6px 0 0;
  line-height: 1.4;
}
.caption-hint strong { font-weight: bold; }

.plugin-sidebar__status {
  font-size: 13px;
  color: #fff;
  min-height: 18px;
  font-family: var(--font-regular);
  opacity: 0.85;
}

/* URL-seksjon: label + input-rad i normal flow (ingen absolute) */
.url-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.url-section__label {
  font-family: var(--font-bold);
  font-size: 13px;
  font-weight: bold;
  color: #fff;
  letter-spacing: 0.02em;
}

.url-section__header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 8px;
}

/* Liten tekst-lenke-knapp — åpner ekstern side i nettleser */
.link-btn {
  background: transparent;
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 12px;
  padding: 2px 0;
  cursor: pointer;
  text-decoration: underline;
  text-decoration-color: rgba(255,255,255,0.5);
  text-underline-offset: 3px;
  transition: text-decoration-color 0.15s, color 0.15s;
}
.link-btn:hover {
  text-decoration-color: #fff;
  color: #fff;
}

.url-row {
  background: var(--bg-input);
  height: 41px;
  border-radius: var(--radius-input);
  padding: 0 4px 0 17px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.url-row__input {
  flex: 1;
  background: transparent;
  border: 0;
  outline: 0;
  height: 100%;
  font-family: var(--font-bold);
  font-size: 13px;
  color: var(--text-input);
  font-weight: bold;
  min-width: 0;
}
.url-row__input::placeholder {
  color: #888;
  font-weight: normal;
}

.btn-tiny {
  background: var(--faktisk-blue);
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 13px;
  height: 30px;
  padding: 0 12px;
  border-radius: var(--radius-input);
  white-space: nowrap;
  transition: background 0.15s;
}
.btn-tiny:hover { background: var(--faktisk-blue-hover); }

/* Eksport-knapper i sidebar — side om side for å spare plass */
.export-row {
  display: flex;
  gap: 8px;
}
.export-row__btn {
  flex: 1;
  min-width: 0;
  padding: 0 8px;
  font-size: 14px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* Prosjekt-rad — dropdown + lagre-knapp stablet vertikalt så de får plass
   i den smale 313px-sidebaren */
.project-row {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.project-select {
  width: 100%;
  height: 36px;
  background: var(--bg-input);
  border: 0;
  border-radius: var(--radius-input);
  padding: 0 32px 0 12px;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 13px;
  color: var(--text-input);
  cursor: pointer;
  appearance: none;
  -webkit-appearance: none;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='12' height='8' viewBox='0 0 12 8'><path d='M1 1l5 5 5-5' stroke='%23313131' stroke-width='2' fill='none' stroke-linecap='round' stroke-linejoin='round'/></svg>");
  background-repeat: no-repeat;
  background-position: right 12px center;
}
.project-select:focus { outline: 2px solid var(--faktisk-blue); }

/* Lagre-knapp tar full bredde av spalten */
.project-row .btn-tiny {
  width: 100%;
  height: 36px;
}

.btn-secondary {
  background: rgba(255,255,255,0.16);
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 15px;
  height: 52px;
  padding: 0 22px;
  border-radius: var(--radius-button);
  transition: background 0.15s;
}
.btn-secondary:hover { background: rgba(255,255,255,0.24); }
.btn-secondary:disabled,
.btn-primary:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* ============================================
   Høyre canvas
   ============================================ */
.plugin-canvas {
  display: flex;
  flex-direction: column;
  gap: 12px;
  overflow: hidden;
  min-width: 0;
}

.canvas-area {
  position: relative;
  flex: 1;
  background: var(--bg-letterbox);
  border-radius: 10px;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.canvas-video {
  display: block;
  max-width: 100%;
  max-height: 100%;
  width: auto;
  height: auto;
  border-radius: 6px;
  background: #000;
}
.canvas-video:not([src]) { display: none; }

.canvas-empty {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
  text-align: center;
}
.canvas-empty p {
  max-width: 420px;
  font-family: var(--font-regular);
  font-size: 16px;
  color: #fff;
  margin: 0;
  line-height: 1.4;
}
.canvas-empty.hidden { display: none; }

/* ============================================
   Tidslinje (dual-handle trim-slider)
   ============================================ */
.timeline {
  flex-shrink: 0;
  padding: 8px 30px 0;
}

.timeline__track {
  position: relative;
  height: 18px;
  background: #6F6F6F;        /* hele tidslinjen — mørkere grå */
  border-radius: 4px;
  cursor: pointer;
}

/* Det valgte klippet — tydelig Faktisk-blå så det er åpenbart hva som havner i embed */
.timeline__selection {
  position: absolute;
  top: 0;
  bottom: 0;
  background: var(--faktisk-blue);
  pointer-events: none;
  z-index: 1;
}

.timeline__handle {
  position: absolute;
  top: -7px;
  bottom: -7px;
  width: 14px;
  background: var(--faktisk-blue);
  border: 2px solid #fff;
  border-radius: 4px;
  cursor: ew-resize;
  transform: translateX(-50%);
  z-index: 3;
  transition: background 0.15s, transform 0.1s;
  box-shadow: 0 2px 6px rgba(0,0,0,0.35);
}
.timeline__handle:hover { background: var(--faktisk-blue-hover); }
.timeline__handle:active { transform: translateX(-50%) scale(1.05); }
.timeline__handle--start { left: 0; }
.timeline__handle--end { left: 100%; }

/* Liten "grip"-indikator inni håndtaket */
.timeline__handle::after {
  content: '';
  position: absolute;
  left: 50%;
  top: 50%;
  width: 2px;
  height: 16px;
  background: rgba(255,255,255,0.85);
  transform: translate(-50%, -50%);
  border-radius: 1px;
}

.timeline__labels {
  display: flex;
  justify-content: space-between;
  margin-top: 8px;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 12px;
  color: #fff;
  opacity: 0.85;
}
.timeline__labels span:nth-child(2) {
  flex: 1;
  text-align: center;
}
